A. Path Params (REST style) <pre><code>// Get user by ID
export const getUserById = async (id) =&gt; {
  try {
    const res = await api.get(`/users/${id}`);
    return res.data;
  } catch (err) {
    console.error(`Error fetching user ${id}:`, err);
    throw err;
  }
};

// Get post by ID
export const getPostById = async (id) =&gt; {
  try {
    return (await api.get(`/posts/${id}`)).data;
  } catch (e) {
    throw e;
  }
};
</code></pre>

B. Query Params (axios params object) <pre><code>// Get posts by userId
export const getPostsByUser = async (userId) =&gt; {
  try {
    const res = await api.get("/posts", { params: { userId } });
    return res.data;
  } catch (err) {
    console.error(err);
    throw err;
  }
};

// Search products by name
export const searchProducts = async (name) =&gt; {
  try {
    const res = await api.get("/products", { params: { name } });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

C. Multiple Query Params <pre><code>// Get orders by userId &amp; status
export const getOrdersByUserAndStatus = async (userId, status) =&gt; {
  try {
    const res = await api.get("/orders", {
      params: { userId, status },
    });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

D. Conditional Params (optional filters) <pre><code>export const getFilteredPosts = async ({ userId, minLikes }) =&gt; {
  try {
    const params = {};
    if (userId) params.userId = userId;
    if (minLikes) params.likes_gte = minLikes; // example for JSON-server filtering
    const res = await api.get("/posts", { params });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

E. Array &amp; Complex Params <pre><code>// Get multiple products by IDs
export const getProductsByIds = async (ids = []) =&gt; {
  try {
    const res = await api.get("/products", {
      params: { id: ids }, // axios will serialize as id=1&amp;id=2
    });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

F. Pagination <pre><code>export const getPaginatedPosts = async (page = 1, limit = 10) =&gt; {
  try {
    const res = await api.get("/posts", {
      params: { _page: page, _limit: limit }, // JSON-server pagination
