    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

A. Basic Payload <pre><code>// Create a new user with dynamic data
export const createUser = async (userData) =&gt; {
  try {
    const res = await api.post("/users", userData);
    return res.data;
  } catch (err) {
    console.error("Error creating user:", err);
    throw err;
  }
};

// Create a new post
export const createPost = async ({ userId, title, content, likes = 0 }) =&gt; {
  try {
    const res = await api.post("/posts", {
      userId,
      title,
      content,
      likes,
    });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

B. Path Params + Body <ul> <li>Useful when the resource belongs to another resource (nested routes).</li> </ul> <pre><code>// Create a comment for a specific post
export const createComment = async (postId, { userId, content }) =&gt; {
  try {
    const res = await api.post(`/posts/${postId}/comments`, {
