    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

D. Multipart/Form-Data (for file uploads) <ul> <li>Needed for images, PDFs, etc.</li> </ul> <pre><code>export const uploadProductImage = async (productId, file) =&gt; {
  try {
    const formData = new FormData();
    formData.append("image", file);

    const res = await api.post(`/products/${productId}/upload`, formData, {
      headers: { "Content-Type": "multipart/form-data" },
    });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

E. Array of Objects as Payload <pre><code>// Bulk create products
