  try {
    const res = await api.post("/products/bulk", products);
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

F. Complex Nested Payload <pre><code>export const createOrderWithDetails = async ({
  userId,
  items,
  shippingAddress,
  paymentMethod,
}) =&gt; {
  try {
    const payload = {
      userId,
      items, // [{ productId, quantity }]
