</code></pre>

G. POST with Default + Override Logic <pre><code>export const createPostWithDefaults = async (data) =&gt; {
  try {
    const defaultPost = {
      likes: 0,
      content: "",
    };
    const payload = { ...defaultPost, ...data }; // Override defaults
    const res = await api.post("/posts", payload);
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

