A. Path Params <pre><code>// Delete user by ID
export const deleteUser = async (id) =&gt; {
  try {
    const res = await api.delete(`/users/${id}`);
    return res.data;
  } catch (err) {
    console.error(`Error deleting user ${id}:`, err);
    throw err;
  }
};

// Delete post by ID
export const deletePost = async (id) =&gt; {
  try {
    return (await api.delete(`/posts/${id}`)).data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

B. Query Params <pre><code>// Delete product by passing query param
export const deleteProductByQuery = async (productId) =&gt; {
  try {
    const res = await api.delete("/products", { params: { id: productId } });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

C. Bulk Delete via Array Payload <pre><code>// Delete multiple products at once
export const bulkDeleteProducts = async (ids) =&gt; {
  try {
    const res = await api.delete("/products/bulk", {
      data: { ids }, // axios DELETE supports "data" for payload
    });
    return res.data;
