D. Nested Resource Delete <pre><code>// Delete a comment from a post
export const deleteComment = async (postId, commentId) =&gt; {
  try {
    const res = await api.delete(`/posts/${postId}/comments/${commentId}`);
    return res.data;
  } catch (err) {
