G. Soft Delete (Mark as Deleted Instead of Removing) <pre><code>// Soft delete a post by patching a deleted flag
export const softDeletePost = async (postId) =&gt; {
  try {
    const res = await api.patch(`/posts/${postId}`, { deleted: true });
    return res.data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

1️⃣ Axios Request Cancellation (AbortController) <ul> <li>Avoids race conditions when multiple requests are fired rapidly (e.g., live search).</li> </ul> <pre><code>let controller;

export const searchPostsLive = async (query) =&gt; {
  if (controller) controller.abort(); // cancel previous request
  controller = new AbortController();

  try {
    const res = await api.get("/posts", {
      params: { q: query },
      signal: controller.signal,
    });
    return res.data;
  } catch (err) {
    if (err.name === "CanceledError") {
      console.log("Request canceled");
    } else {
      throw err;
    }
  }
};
</code></pre>

2️⃣ Axios Interceptors (Auth, Logging, Error Handling) <ul> <li>Global handling for tokens, logs, and error transformations.</li> </ul> <pre><code>api.interceptors.request.use((config) =&gt; {
  const token = localStorage.getItem("token");
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (response) =&gt; response,
  (error) =&gt; {
    if (error.response?.status === 401) {
      console.warn("Unauthorized, redirecting to login...");
    }
    return Promise.reject(error);
  }
);
</code></pre>  <p>Token in localStorage is shown for simplicity only</p> <p>This example (and the <code>axiosClient.js</code> setup later in this chapter) reads the JWT from <code>localStorage</code>. That is convenient, but <code>localStorage</code> is accessible to any JavaScript on the page, so a single XSS flaw lets an attacker exfiltrate the token. For production, prefer an HttpOnly, Secure, SameSite cookie set by the server (send it automatically with <code>withCredentials: true</code>), since JavaScript cannot read it. See the Authentication chapter for details.</p>

3️⃣ Parallel API Calls (Promise.all) <ul> <li>Fetch multiple resources at once for better performance.</li> </ul> <pre><code>export const getDashboardData = async () =&gt; {
  try {
    const [users, posts, products] = await Promise.all([
      api.get("/users"),
      api.get("/posts"),
      api.get("/products"),
    ]);

    return {
      users: users.data,
      posts: posts.data,
      products: products.data,
    };
  } catch (err) {
    throw err;
  }
};
</code></pre>

4️⃣ Dependent (Sequential) Requests <ul> <li>Where the second request depends on the first request’s data.</li> </ul> <pre><code>export const getUserWithPosts = async (userId) =&gt; {
  try {
    const user = await api.get(`/users/${userId}`);
    const posts = await api.get("/posts", { params: { userId } });
    return { ...user.data, posts: posts.data };
  } catch (err) {
    throw err;
  }
};
</code></pre>

5️⃣ Retry Failed Requests with Exponential Backoff <ul> <li>Handles flaky network/API failures.</li> </ul> <pre><code>export const fetchWithRetry = async (endpoint, retries = 3, delay = 1000) =&gt; {
  try {
    const res = await api.get(endpoint);
    return res.data;
  } catch (err) {
    if (retries &gt; 0) {
      await new Promise((resolve) =&gt; setTimeout(resolve, delay));
      return fetchWithRetry(endpoint, retries - 1, delay * 2); // exponential backoff
    }
    throw err;
  }
};
</code></pre>

6️⃣ Request Timeouts <ul> <li>Abort request if it takes too long.</li> </ul> <pre><code>export const getFastResponse = async () =&gt; {
  try {
    const res = await api.get("/products", { timeout: 3000 });
    return res.data;
  } catch (err) {
    if (err.code === "ECONNABORTED") {
      console.warn("Request timed out");
    }
    throw err;
  }
};
</code></pre>

7️⃣ Pagination &amp; Infinite Scroll Loader <ul> <li>Advanced API with stateful pagination.</li> </ul> <pre><code>export const getPaginatedUsers = async (page, limit = 10) =&gt; {
  try {
    const res = await api.get("/users", { params: { _page: page, _limit: limit } });
    return {
      data: res.data,
      totalCount: parseInt(res.headers["x-total-count"], 10) || 0,
    };
  } catch (err) {
    throw err;
  }
};
</code></pre>

8️⃣ Batch Request Processing <ul> <li>Send multiple related changes in one API call.</li> </ul> <pre><code>export const batchUpdateOrders = async (updates) =&gt; {
  try {
    return (await api.patch("/orders/batch", updates)).data;
  } catch (err) {
    throw err;
  }
};
</code></pre>

9️⃣ File Upload with Progress Tracking <ul> <li>Common for dashboards and CMS systems.</li> </ul> <pre><code>export const uploadFileWithProgress = async (file, onProgress) =&gt; {
  try {
    const formData = new FormData();
    formData.append("file", file);

    const res = await api.post("/upload", formData, {
      headers: { "Content-Type": "multipart/form-data" },
      onUploadProgress: (progressEvent) =&gt; {
        const percent = Math.round((progressEvent.loaded * 100) / (progressEvent.total || 1));
        onProgress(percent);
      },
    });
    return res.data;
  } catch (err) {
    throw err;
  }

};
</code></pre>

🔟 Optimistic UI Updates <ul> <li>Update UI instantly before API confirmation.</li> </ul> <pre><code>export const likePostOptimistic = async (postId, currentLikes, setLikes) =&gt; {
  // Instantly update UI
  setLikes(currentLikes + 1);

  try {
    await api.patch(`/posts/${postId}`, { likes: currentLikes + 1 });
  } catch (err) {
    // Revert if failed
    setLikes(currentLikes);
    throw err;
  }
};
</code></pre>

1️⃣1️⃣ Cache + LocalStorage Fallback <ul> <li>Reduces API calls by caching results.</li> </ul> <pre><code>export const getCachedUsers = async () =&gt; {
  const cache = localStorage.getItem("usersCache");
  if (cache) return JSON.parse(cache);

  const res = await api.get("/users");
  localStorage.setItem("usersCache", JSON.stringify(res.data));
  return res.data;
};
</code></pre>

1️⃣2️⃣ Axios Instance per Feature <ul> <li>Multiple axios.create instances for microservice APIs.</li> </ul> <pre><code>export const authApi = axios.create({ baseURL: "https://auth.example.com" });
export const productApi = axios.create({ baseURL: "https://products.example.com" });
</code></pre>

React (Vite / CRA) <pre><code>src/
│
