export const createUser = (data) =&gt; axiosClient.post('/users', data);
export const updateUser = (id, data) =&gt; axiosClient.put(`/users/${id}`, data);
export const deleteUser = (id) =&gt; axiosClient.delete(`/users/${id}`);
